def build_index_from_json_documents(
    json_file_path: str,
    index_path: str,
    text_field: str = "text",
    metadata_fields: Optional[List[str]] = None,
    backend_name: str = "hnsw"
) -> str:
    """Build a LEANN index from a JSON file containing documents."""

    # Check if JSON file exists
    json_path = Path(json_file_path)
    if not json_path.exists():
        raise FileNotFoundError(f"JSON file not found: {json_file_path}")

    # Read and validate JSON file
    try:
        with open(json_file_path, 'r', encoding='utf-8') as f:
            documents = json.load(f)
    except json.JSONDecodeError:
        raise ValueError("Invalid JSON file")

    # Validate documents structure
    if not isinstance(documents, list) or len(documents) == 0:
        raise ValueError("JSON file must contain a non-empty list of documents")

    # Check if all documents have the required text field
    for i, doc in enumerate(documents):
        if not isinstance(doc, dict) or text_field not in doc:
            raise ValueError(f"Document at index {i} missing required field '{text_field}'")

    # Determine metadata fields to include
    if metadata_fields is None:
        # Include all fields except the text field
        metadata_fields = [field for field in documents[0].keys() if field != text_field]
    else:
        # Validate that specified metadata fields exist in documents
        for field in metadata_fields:
            if field not in documents[0]:
                # If a field is specified but not present in all documents, we'll handle it during processing
                pass  # Proceed as is, since some documents may not have the field

    # Prepare texts and metadata for indexing
    texts = []
    metadata_list = []

    for doc in documents:
        text = doc[text_field]
        texts.append(text)

        # Extract metadata based on the specified fields
        metadata = {}
        if metadata_fields is None:
            # Include all fields except text_field
            for field in doc.keys():
                if field != text_field:
                    metadata[field] = doc[field]
        else:
            # Use specified metadata fields
            for field in metadata_fields:
                if field in doc:
                    metadata[field] = doc[field]
        metadata_list.append(metadata)

    # Build the LEANN index
    builder = LeannBuilder(backend_name=backend_name)
    for text, metadata in zip(texts, metadata_list):
        builder.add_text(text, metadata=metadata)
    builder.build_index(index_path)

    return index_path

