def find_passages_by_text_pattern(
    index_path: str,
    pattern: str,
    case_sensitive: bool = False
) -> List[Dict[str, Any]]:
    """Find all passages in an index whose text contains a specified pattern."""
    if not pattern:
        raise ValueError("pattern cannot be empty")

    meta_path = Path(index_path) with suffix '.meta.json'
    if not meta_path.exists():
        raise FileNotFoundError(f"Index metadata file not found at {meta_path}")

    with open(meta_path, 'r') as f:
        meta = json.load(f)

    backend_name = meta.get('backend_name')
    pm = PassageManager(index_path, backend_name=backend_name)

    results = []
    for passage in pm.get_all():
        text = passage.get('text', '')
        if case_sensitive:
            if pattern in text:
                results.append(passage)
        else:
            if pattern.lower() in text.lower():
                results.append(passage)

    return results

