def verify_index_integrity(index_path: str) -> Dict[str, Any]:
    meta_path = Path(f"{index_path}.meta.json")

    if not meta_path.exists():
        raise FileNotFoundError(f"Index metadata file not found at {meta_path}")

    try:
        with open(meta_path, 'r') as f:
            metadata = json.load(f)
    except (json.JSONDecodeError, IOError) as e:
        errors = [f"Failed to read metadata: {str(e)}"]
        return {
            "is_valid": False,
            "passage_count": 0,
            "metadata_file_exists": True,
            "errors": errors
        }

    required_fields = ['passage_count', 'backend_name']
    errors = []

    for field in required_fields:
        if field not in metadata:
            errors.append(f"Missing required field: {field}")

    if 'passage_count' in metadata:
        passage_count = metadata['passage_count']
        if not isinstance(passage_count, int) or passage_count < 0:
            errors.append("Invalid passage_count")

    index_file = Path(index_path)
    if not index_file.exists():
        errors.append(f"Index file not found at {index_file}")

    is_valid = len(errors) == 0

    return {
        "is_valid": is_valid,
        "passage_count": metadata.get('passage_count', 0),
        "metadata_file_exists": meta_path.exists(),
        "errors": errors
    }

