def get_index_statistics(index_path: str) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index."""
    try:
        searcher = LeannSearcher(index_path)
        pm = searcher.passage_manager
        passages = pm.get_all()

        field_names = set()
        field_value_counts = defaultdict(Counter)

        for passage in passages:
            metadata = passage.metadata
            for field_name, value in metadata.items():
                field_names.add(field_name)
                field_value_counts[field_name][value] += 1

        return {
            "total_passages": len(passages),
            "metadata_fields": sorted(field_names),
            "field_value_counts": dict(field_value_counts)
        }
    except FileNotFoundError:
        raise FileNotFoundError(f"Index metadata file not found at {index_path}")

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields."""
    try:
        searcher = LeannSearcher(index_path)
        pm = searcher.passage_manager
        passages = pm.get_all()

        total_passages = len(passages)
        if total_passages == 0:
            return {
                "coverage_percentage": 0.0,
                "field_coverage": {field: 0.0 for field in required_fields},
                "missing_fields": required_fields.copy()
            }

        # Collect all field names from all passages
        all_fields = set()
        for passage in passages:
            all_fields.update(passage.metadata.keys())

        # Check which required fields are missing entirely
        missing_fields = [field for field in required_fields if field not in all_fields]

        # Calculate coverage for each required field
        field_coverage = {}
        for field in required_fields:
            covered_count = sum(1 for passage in passages if field in passage.metadata)
            field_coverage[field] = (covered_count / total_passages) * 100

        # Calculate overall coverage (passages that have ALL required fields)
        all_required_covered = sum(1 for passage in passages 
                                  if all(field in passage.metadata for field in required_fields))
        coverage_percentage = (all_required_covered / total_passages) * 100

        return {
            "coverage_percentage": round(coverage_percentage, 2),
            "field_coverage": field_coverage,
            "missing_fields": missing_fields
        }
    except FileNotFoundError:
        raise FileNotFoundError(f"Index metadata file not found at {index_path}")

import signal
from leann.api import LeannSearcher, SearchResult
from typing import List

def search_with_timeout(
    index_path: str,
    query: str,
    top_k: int = 10,
    timeout_seconds: float = 5.0
) -> List[SearchResult]:
    """Search in an index with a timeout constraint."""
    if timeout_seconds <= 0:
        raise ValueError("timeout_seconds must be greater than 0")

    try:
        searcher = LeannSearcher(index_path)
    except FileNotFoundError:
        raise FileNotFoundError(f"Index file not found: {index_path}")

    def timeout_handler(signum, frame):
        raise Exception("timeout")

    original_handler = signal.signal(signal.SIGALRM, timeout_handler)
    signal.alarm(int(timeout_seconds))

    try:
        results = searcher.search(query, top_k=top_k)
        return results
    except Exception as e:
        if "timeout" in str(e):
            signal.alarm(0)
            signal.signal(signal.SIGALRM, original_handler)
            return []
        else:
            raise
    finally:
        signal.alarm(0)
        signal.signal(signal.SIGALRM, original_handler)

def timeout_handler(signum, frame):
    """Signal handler for timeout."""
    raise Exception("timeout")

