    pm = PassageManager.load(index_path)
    matching_passages = []

    for passage in pm.passages:
        text = passage['text']
        if case_sensitive:
            if search_text in text:
                matching_passages.append(passage)
        else:
            if search_text.lower() in text.lower():
                matching_passages.append(passage)

    return matching_passages

from typing import List, Dict, Any
from leann.api import LeannSearcher, SearchResult

def search_with_field_priority(
    index_path: str,
    query: str,
    priority_field: str,
    priority_values: List[Any],
    top_k: int = 10
) -> List[SearchResult]:
    """Search in an index and prioritize results based on field value order."""
    try:
        searcher = LeannSearcher(index_path)
    except Exception as e:
        if "No such file or directory" in str(e):
            raise FileNotFoundError(f"Index file not found: {index_path}")
        else:
            raise  # Re-raise other exceptions

    if not priority_values:
        raise ValueError("priority_values cannot be empty")

    results = searcher.search(query, top_k=top_k)

    # Sort by priority (earlier values in priority_values have higher priority)
    # Then by score (descending)
    sorted_results = sorted(
        results,
        key=lambda r: (
            priority_values.index(r.metadata.get(priority_field)) 
            if priority_field in r.metadata and r.metadata[priority_field] in priority_values 
            else len(priority_values),
            -r.score
        )
    )

    return sorted_results[:top_k]
